// LAYER 1+2: Extract & Validate (§4.1 PRE-validate)
// Zero-throw: returns Standard Contract error, never throws

const raw = $input.first().json;
const input = (raw.body && typeof raw.body === 'object') ? raw.body : raw;

function ve(code, msg) {
  return [{ json: {
    success: false, error_code: code, error_message: msg, data: null,
    _meta: { source: 'DB_Get_Providers_By_Service', timestamp: new Date().toISOString(), workflow_id: $workflow.id },
    _exit_early: true
  }}];
}

// === SERVICE_ID VALIDATION (required) ===
let service_id;
if (input.service_id === undefined || input.service_id === null) {
  return ve('MISSING_FIELD', 'service_id is required');
}
if (typeof input.service_id === 'string') {
  const trimmed = input.service_id.trim();
  const INT_RE = /^\d+$/;
  if (!INT_RE.test(trimmed)) return ve('INVALID_TYPE', 'service_id must be a positive integer');
  service_id = parseInt(trimmed);
} else if (typeof input.service_id === 'number') {
  service_id = input.service_id;
  if (!Number.isInteger(service_id) || service_id < 1) return ve('INVALID_TYPE', 'service_id must be a positive integer');
} else {
  return ve('INVALID_TYPE', 'service_id must be a number or numeric string');
}

return [{ json: {
  success: true,
  service_id,
  _validated: true
}}];

// Gate: _exit_early items skip to Format Response
// Valid items: build providers-by-service query
const input = $input.first().json;

if (input._exit_early) {
  return [{ json: { ...input, providers: [] } }];
}

const { service_id } = input;

// Build query to get providers for a specific service
// JOIN providers with provider_services to get only providers offering this service
const providers_query = `
  SELECT DISTINCT p.id, p.name, p.email, p.active, p.created_at
  FROM providers p
  INNER JOIN provider_services ps ON p.id = ps.provider_id
  WHERE ps.service_id = ${service_id}::int
  ORDER BY p.name;
`;

return [{ json: {
  ...input,
  providers_query,
  service_id
}}];

// GATE: Only process items with _validated === true
const input = $input.first().json;

if (input._exit_early) {
  return [];
}

return [{ json: input }];

// Handle DB error during providers query
const e = $input.first().json;
const upstreamData = $('Build Providers Query').isExecuted ? $('Build Providers Query').first().json : {};
let error_code = 'DB_QUERY_ERROR';
let error_message = e.message || e.error?.message || 'Database query error';

if (error_message.includes('connection') || error_message.includes('ECONNREFUSED')) {
  error_code = 'DB_CONNECTION_ERROR';
  error_message = 'Database connection failed';
} else if (error_message.includes('timeout')) {
  error_code = 'DB_TIMEOUT';
  error_message = 'Database query timeout';
} else if (error_message.includes('relation') && error_message.includes('does not exist')) {
  error_code = 'TABLE_NOT_FOUND';
  if (error_message.includes('provider_services')) {
    error_message = 'provider_services junction table does not exist';
  } else {
    error_message = 'Providers table does not exist';
  }
}

return [{ json: {
  ...upstreamData,
  success: false, error_code, error_message, data: null,
  _meta: { source: 'DB_Get_Providers_By_Service', timestamp: new Date().toISOString(), workflow_id: $workflow.id }
}}];

// Format providers response
const items = $input.all();
const upstreamData = $('Build Providers Query').isExecuted ? $('Build Providers Query').first().json : {};

// Map all provider rows
const providers = items.map(item => ({
  id: item.json.id,
  name: item.json.name,
  email: item.json.email,
  active: item.json.active,
  created_at: item.json.created_at
}));

return [{ json: {
  success: true,
  error_code: null,
  error_message: null,
  data: {
    providers,
    total: providers.length,
    service_id: upstreamData.service_id
  },
  _meta: {
    source: 'DB_Get_Providers_By_Service',
    timestamp: new Date().toISOString(),
    workflow_id: $workflow.id
  }
}}];

// UNIFIED OUTPUT — Standard Contract (§3.2)
const input = $input.first().json;

// Process items that have data OR error_code set
if (input.data !== undefined || input.error_code !== undefined) {
  return [{ json: {
    success: input.success === true,
    error_code: input.error_code || null,
    error_message: input.error_message || null,
    data: input.data || null,
    _meta: input._meta || {
      source: 'DB_Get_Providers_By_Service',
      timestamp: new Date().toISOString(),
      workflow_id: $workflow.id
    }
  }}];
}

// Otherwise, pass-through item — skip it
return [];
